import Marquee from "react-fast-marquee";
import { motion } from "framer-motion";

const videoMarqueeItems = [
  { id: "v1", src: "/assets/videos/cooking.mp4", alt: "Cooking" },
  { id: "v2", src: "/assets/videos/vid2.mp4", alt: "Vid 2" },
  { id: "v3", src: "/assets/videos/vid3.mp4", alt: "Vid 3" },
  { id: "v4", src: "/assets/videos/vid5.mp4", alt: "Vid 5" },
  { id: "v5", src: "/assets/videos/vid6.mp4", alt: "Vid 6" }
];

const placeholderImages = [
  { id: "i1", src: "/assets/amb.jpg", alt: "Ambience" },
  { id: "i2", src: "/assets/apr.jpg", alt: "Aperitif" },
  { id: "i3", src: "/assets/ballent.jpg", alt: "Ballentine" },
  { id: "i4", src: "/assets/bl.jpg", alt: "Bar Lounge" },
  { id: "i5", src: "/assets/bn.jpg", alt: "Bar Night" },
  { id: "i6", src: "/assets/dj.jpg", alt: "DJ Night" },
  { id: "i7", src: "/assets/dri.jpg", alt: "Drinks" },
  { id: "i8", src: "/assets/f1.jpg", alt: "Food" },
  { id: "i9", src: "/assets/grp.jpg", alt: "Group" },
  { id: "i10", src: "/assets/nod.jpg", alt: "Night Out" }
];

const MovingGallery = () => {
  const renderVideo = (video) => (
    <div key={video.id} style={{ marginRight: '0', display: 'inline-block', width: '210px', height: '350px' }}>
      <video
        preload="metadata"
        src={video.src}
        style={{ width: '100%', height: '100%', objectFit: 'cover', borderRadius: '1rem', boxShadow: '0 20px 40px rgba(0,0,0,0.5)' }}
        muted
        autoPlay
        loop
        playsInline
      />
    </div>
  );

  const renderImage = (image) => (
    <motion.img
      key={image.id}
      src={image.src}
      alt={image.alt}
      style={{ width: '290px', height: '180px', objectFit: 'cover', borderRadius: '0.75rem', marginRight: '0', display: 'inline-block' }}
      className="grayscale hover:grayscale-0 hover:scale-105 transition-all duration-300 shadow-lg"
      loading="lazy"
      whileHover={{ scale: 1.02 }}
    />
  );

  return (
    <section className="py-20 bg-black overflow-hidden">
      <div className="text-center mb-24">
        <span className="inline-block px-6 py-3 font-accent text-gold text-sm tracking-[0.3em] uppercase mb-8 bg-black/30 rounded-full">
          Experience The Vibe
        </span>
        <h2 className="font-heading text-5xl md:text-6xl lg:text-7xl text-white tracking-tight leading-none">
          Corridor in Motion
        </h2>
      </div>

      {/* Video Marquee Seamless */}
      <div style={{ padding: '0 2rem' }}>
        <Marquee speed={28} gradient={false} pauseOnHover={true}>
          {videoMarqueeItems.map(renderVideo)}
          {videoMarqueeItems.map(renderVideo)}
        </Marquee>
      </div>

      {/* Images LTR Seamless */}
      <div style={{ padding: '0 2rem', marginTop: '4rem' }}>
        <Marquee speed={55} gradient={false} pauseOnHover={true}>
          {placeholderImages.map(renderImage)}
        </Marquee>
      </div>

      {/* Images RTL Seamless */}
      <div style={{ padding: '0 2rem', marginTop: '4rem' }}>
        <Marquee speed={55} direction="right" gradient={false} pauseOnHover={true}>
          {placeholderImages.slice(0,6).map(renderImage)}
        </Marquee>
      </div>
    </section>
  );
};

export default MovingGallery;
